/******************************************************************************************************************//**
 *  Get pointer to image selected at build time.
 *
 * @retval Pointer to selected image data.
 *********************************************************************************************************************/
const uint8_t * r_ble_gtl_image_get(void)
{
    return g_da1453x_boot_image;
}
/******************************************************************************************************************//**
 *  Get length of image selected at build time.
 *
 * @retval Length of image in bytes.
 *********************************************************************************************************************/
uint16_t r_ble_gtl_image_get_len(void)
{
    return sizeof(g_da1453x_boot_image);
}
/******************************************************************************************************************//**
 *  Calculate CRC of image selected at build time.
 *
 * @retval CRC of image.
 *********************************************************************************************************************/
uint8_t r_ble_gtl_image_get_crc(void)
{
    uint8_t  crc = 0;
    uint16_t i;
    for (i = 0; i < sizeof(g_da1453x_boot_image); i++)
    {
        crc ^= g_da1453x_boot_image[i];
    }
    return crc;
}
